#include <cuda_runtime.h>
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>

__global__ void warmup_kernel(float* data, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        float val = data[idx];
        // Perform many FMA operations to create sustained load
        for (int i = 0; i < 10000; i++) {
            val = fmaf(val, val, val);
        }
        data[idx] = val;
    }
}

__global__ void measure_kernel(float* data, int n, unsigned long long* start_clock, unsigned long long* end_clock) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        *start_clock = clock64();
    }

    __syncthreads();

    if (idx < n) {
        float val = data[idx];
        // Perform many FMA operations to maintain high utilization
        for (int i = 0; i < 10000; i++) {
            val = fmaf(val, val, val);
        }
        data[idx] = val;
    }

    __syncthreads();

    if (threadIdx.x == 0 && blockIdx.x == 0) {
        *end_clock = clock64();
    }
}

int main() {
    int device;
    cudaGetDevice(&device);

    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, device);

    int numSMs = prop.multiProcessorCount;
    int blockSize = 256;
    int numBlocks = numSMs * 8; // Use more blocks than SMs to ensure occupancy

    int n = numBlocks * blockSize;

    float* d_data;
    cudaMalloc(&d_data, n * sizeof(float));
    cudaMemset(d_data, 1, n * sizeof(float));

    unsigned long long* d_start_clock;
    unsigned long long* d_end_clock;
    cudaMalloc(&d_start_clock, sizeof(unsigned long long));
    cudaMalloc(&d_end_clock, sizeof(unsigned long long));

    // Warmup phase - run for at least 500ms of sustained compute
    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    // Launch warmup kernels multiple times to ensure boost clock is reached
    for (int i = 0; i < 10; i++) {
        warmup_kernel<<<numBlocks, blockSize>>>(d_data, n);
    }
    cudaDeviceSynchronize();

    // Now perform the actual measurement
    std::vector<float> frequencies;

    for (int trial = 0; trial < 5; trial++) {
        cudaEventRecord(start_event);

        measure_kernel<<<numBlocks, blockSize>>>(d_data, n, d_start_clock, d_end_clock);

        cudaEventRecord(stop_event);
        cudaEventSynchronize(stop_event);

        float elapsed_ms;
        cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);

        unsigned long long start_clk, end_clk;
        cudaMemcpy(&start_clk, d_start_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
        cudaMemcpy(&end_clk, d_end_clock, sizeof(unsigned long long), cudaMemcpyDeviceToHost);

        unsigned long long clock_diff = end_clk - start_clk;

        // Calculate frequency in MHz
        float freq_mhz = static_cast<float>(clock_diff) / (elapsed_ms * 1000.0f);
        frequencies.push_back(freq_mhz);
    }

    // Get median frequency
    std::sort(frequencies.begin(), frequencies.end());
    float median_freq = frequencies[frequencies.size() / 2];

    std::cout << median_freq << std::endl;

    cudaFree(d_data);
    cudaFree(d_start_clock);
    cudaFree(d_end_clock);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    return 0;
}

