#include <cuda_runtime.h>
#include <iostream>
#include <vector>

#define SHARED_MEM_SIZE 4096  // 4KB per block
#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 64
#define ITERATIONS 100

__global__ void shared_memory_bandwidth_kernel(unsigned long long* start_cycle, unsigned long long* end_cycle, volatile float* dummy_output) {
    __shared__ float smem[SHARED_MEM_SIZE / sizeof(float)];

    int tid = threadIdx.x;
    int global_tid = blockIdx.x * blockDim.x + threadIdx.x;

    if (global_tid == 0) {
        *start_cycle = clock64();
    }

    // Initialize shared memory
    for (int i = tid; i < SHARED_MEM_SIZE / sizeof(float); i += THREADS_PER_BLOCK) {
        smem[i] = static_cast<float>(global_tid + i);
    }
    __syncthreads();

    // Perform multiple read/write operations to saturate bandwidth
    for (int iter = 0; iter < ITERATIONS; iter++) {
        for (int i = 0; i < 100; i++) {
            // Read and write to different locations to avoid compiler optimizations
            int idx = (tid + i) % (SHARED_MEM_SIZE / sizeof(float));
            float val = smem[idx];
            smem[(idx + 1) % (SHARED_MEM_SIZE / sizeof(float))] = val + 1.0f;
        }
        __syncthreads();
    }

    if (global_tid == 0) {
        *end_cycle = clock64();
    }

    // Prevent optimization
    if (tid < 32) {
        *dummy_output = smem[tid];
    }
}

int main() {
    // Allocate device memory for cycle counters
    unsigned long long *d_start_cycle, *d_end_cycle;
    float *d_dummy_output;

    cudaMalloc(&d_start_cycle, sizeof(unsigned long long));
    cudaMalloc(&d_end_cycle, sizeof(unsigned long long));
    cudaMalloc(&d_dummy_output, sizeof(float));

    // Warmup run
    shared_memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_start_cycle, d_end_cycle, d_dummy_output);
    cudaDeviceSynchronize();

    // Actual measurement
    cudaEvent_t start_event, stop_event;
    cudaEventCreate(&start_event);
    cudaEventCreate(&stop_event);

    cudaEventRecord(start_event);

    shared_memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_start_cycle, d_end_cycle, d_dummy_output);

    cudaEventRecord(stop_event);
    cudaEventSynchronize(stop_event);

    // Calculate timing
    float elapsed_ms = 0;
    cudaEventElapsedTime(&elapsed_ms, start_event, stop_event);

    // Calculate total bytes transferred
    size_t bytes_per_access = sizeof(float) * 2; // read + write
    size_t accesses_per_thread = ITERATIONS * 100;
    size_t total_threads = NUM_BLOCKS * THREADS_PER_BLOCK;
    size_t total_bytes = total_threads * accesses_per_thread * bytes_per_access;

    float elapsed_seconds = elapsed_ms / 1000.0f;
    float bandwidth_gbps = (float)total_bytes / (elapsed_seconds * 1e9);

    std::cout << bandwidth_gbps << std::endl;

    // Cleanup
    cudaFree(d_start_cycle);
    cudaFree(d_end_cycle);
    cudaFree(d_dummy_output);
    cudaEventDestroy(start_event);
    cudaEventDestroy(stop_event);

    return 0;
}

