#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <vector>
#include <random>

#define NODE_SIZE 128 // One cache line
#define NODE_DATA_SIZE (NODE_SIZE / sizeof(int))
#define DRAM_ARRAY_SIZE_MB 64
#define DRAM_NODE_COUNT ((DRAM_ARRAY_SIZE_MB * 1024 * 1024) / NODE_SIZE)
#define CHASE_STEPS 10000
#define ITERATIONS 50

__global__ void initialize_nodes(int* nodes, int num_nodes) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_nodes) {
        nodes[idx * NODE_DATA_SIZE] = (idx + 1) % num_nodes;
    }
}

__global__ void shuffle_nodes(int* nodes, int* indices, int num_nodes) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_nodes) {
        int temp = indices[idx];
        int new_idx = nodes[temp * NODE_DATA_SIZE];
        nodes[temp * NODE_DATA_SIZE] = nodes[new_idx * NODE_DATA_SIZE];
        nodes[new_idx * NODE_DATA_SIZE] = nodes[temp * NODE_DATA_SIZE];
    }
}

__global__ void flush_cache(int* flush_buffer, int buffer_size) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    for (int i = tid; i < buffer_size; i += stride) {
        flush_buffer[i]++;
    }
}

__global__ void pointer_chase_dram(int* nodes, long long* times, int* results, int num_nodes, int chase_steps) {
    if (threadIdx.x == 0 && blockIdx.x == 0) {
        volatile int* vnodes = (volatile int*)nodes;
        long long start_time = clock64();

        int idx = 0;
        for (int i = 0; i < chase_steps; i++) {
            idx = vnodes[idx * NODE_DATA_SIZE];
            // Ensure idx stays within bounds
            idx = idx % num_nodes;
        }

        long long end_time = clock64();
        times[0] = end_time - start_time;
        results[0] = idx; // Prevent optimization
    }
}

__global__ void generate_random_permutation(int* nodes, int num_nodes, unsigned long seed) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= num_nodes) return;

    // Simple linear congruential generator for GPU
    unsigned long val = seed ^ tid;
    val = val * 1103515245UL + 12345UL;
    val ^= val >> 16;
    val *= 1103515245UL + 12345UL;

    int target = val % num_nodes;
    if (target != tid) {
        int temp = nodes[tid * NODE_DATA_SIZE];
        nodes[tid * NODE_DATA_SIZE] = nodes[target * NODE_DATA_SIZE];
        nodes[target * NODE_DATA_SIZE] = temp;
    }
}

int main() {
    int* h_nodes = (int*)malloc(DRAM_NODE_COUNT * NODE_DATA_SIZE * sizeof(int));
    int* d_nodes;
    int* d_flush_buffer;
    long long* d_times;
    int* d_results;

    cudaMalloc(&d_nodes, DRAM_NODE_COUNT * NODE_DATA_SIZE * sizeof(int));
    cudaMalloc(&d_flush_buffer, 32 * 1024 * 1024 * sizeof(int)); // 32MB flush buffer
    cudaMalloc(&d_times, sizeof(long long));
    cudaMalloc(&d_results, sizeof(int));

    // Initialize nodes sequentially
    for (int i = 0; i < DRAM_NODE_COUNT; i++) {
        h_nodes[i * NODE_DATA_SIZE] = (i + 1) % DRAM_NODE_COUNT;
        for (int j = 1; j < NODE_DATA_SIZE; j++) {
            h_nodes[i * NODE_DATA_SIZE + j] = 0;
        }
    }

    cudaMemcpy(d_nodes, h_nodes, DRAM_NODE_COUNT * NODE_DATA_SIZE * sizeof(int), cudaMemcpyHostToDevice);

    // Generate random permutation on GPU
    dim3 block(256);
    dim3 grid((DRAM_NODE_COUNT + block.x - 1) / block.x);

    for (int round = 0; round < 3; round++) {
        generate_random_permutation<<<grid, block>>>(d_nodes, DRAM_NODE_COUNT, time(NULL) + round);
        cudaDeviceSynchronize();
    }

    std::vector<long long> measurements;

    for (int iter = 0; iter < ITERATIONS; iter++) {
        // Flush L2 cache
        dim3 flush_block(256);
        dim3 flush_grid((32 * 1024 * 1024 + flush_block.x - 1) / flush_block.x);
        flush_cache<<<flush_grid, flush_block>>>(d_flush_buffer, 32 * 1024 * 1024);
        cudaDeviceSynchronize();

        // Run pointer chase
        pointer_chase_dram<<<1, 1>>>(d_nodes, d_times, d_results, DRAM_NODE_COUNT, CHASE_STEPS);
        cudaDeviceSynchronize();

        long long time;
        cudaMemcpy(&time, d_times, sizeof(long long), cudaMemcpyDeviceToHost);
        measurements.push_back(time);
    }

    // Calculate median
    std::sort(measurements.begin(), measurements.end());
    long long median_time = measurements[measurements.size() / 2];

    double latency_cycles = (double)median_time / CHASE_STEPS;

    printf("%.2f\n", latency_cycles);

    free(h_nodes);
    cudaFree(d_nodes);
    cudaFree(d_flush_buffer);
    cudaFree(d_times);
    cudaFree(d_results);

    return 0;
}

