#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#define WARP_SIZE 32
#define NUM_THREADS_PER_BLOCK 256
#define NUM_WARPS_PER_BLOCK (NUM_THREADS_PER_BLOCK / WARP_SIZE)
#define SHARED_MEM_SIZE 8192
#define NUM_ACCESS_ITERATIONS 100

__global__ void conflict_free_kernel(unsigned long long* result) {
    __shared__ float smem[SHARED_MEM_SIZE];

    unsigned int tid = threadIdx.x;
    unsigned long long start_cycle, end_cycle;

    // Initialize shared memory
    for(int i = tid; i < SHARED_MEM_SIZE; i += NUM_THREADS_PER_BLOCK) {
        smem[i] = (float)(i + 1);
    }
    __syncthreads();

    start_cycle = clock64();

    float temp = 0.0f;
    for(int iter = 0; iter < NUM_ACCESS_ITERATIONS; iter++) {
        // Conflict-free access: each thread accesses its own bank
        temp += smem[tid];
        smem[tid] = temp;
        __syncthreads(); // Ensure writes complete before next iteration
    }

    end_cycle = clock64();

    if(tid == 0) {
        *result = end_cycle - start_cycle;
    }
}

__global__ void conflict_kernel(unsigned long long* result) {
    __shared__ float smem[SHARED_MEM_SIZE];

    unsigned int tid = threadIdx.x;
    unsigned long long start_cycle, end_cycle;

    // Initialize shared memory
    for(int i = tid; i < SHARED_MEM_SIZE; i += NUM_THREADS_PER_BLOCK) {
        smem[i] = (float)(i + 1);
    }
    __syncthreads();

    start_cycle = clock64();

    float temp = 0.0f;
    for(int iter = 0; iter < NUM_ACCESS_ITERATIONS; iter++) {
        // Create bank conflict: all threads in warp access same bank
        // Bank = (address / 4) % 32 (assuming 4-byte floats)
        // If we access smem[tid * 32], all will go to bank (tid * 32 / 4) % 32 = (tid * 8) % 32
        // To force same bank, we need addresses that map to same bank
        // For simplicity, let's make all threads access bank 0 by using addresses that are multiples of 32*4=128
        // Address = tid * 32 maps to bank (tid * 32 / 4) % 32 = (tid * 8) % 32
        // To force same bank, we can use address tid * 32 * 4 = tid * 128 to always hit bank 0
        // Actually, for float (4 bytes), address tid*32 maps to bank (tid*32/4)%32 = (tid*8)%32
        // So for warp 0: threads 0-31 access banks (0*8%32=0, 1*8%32=8, 2*8%32=16, 3*8%32=24, 4*8%32=0, ...)
        // To force all threads in a warp to access same bank, we need to align to the same bank
        // All threads accessing address 0 would go to bank 0 (but this is not what we want)
        // We want each thread to access a different address but all in the same bank
        // Bank = (addr / 4) % 32
        // So if addr = tid * 32, then bank = (tid * 32 / 4) % 32 = (tid * 8) % 32
        // For threads 0-31 in a warp, this gives: 0,8,16,24,0,8,16,24,0,8,16,24,0,8,16,24,0,8,16,24,0,8,16,24,0,8,16,24,0,8,16,24
        // This creates 4-way conflicts (4 threads per bank)

        // Let's try another approach: force all threads in warp to access same bank
        // Bank 0: addresses 0,4,8,12,...,124 (divisible by 4, mod 128 = 0,4,8,12...)
        // To make all threads access bank 0: use address tid * 128 (since (tid*128)/4 % 32 = 0)
        temp += smem[tid * 32];  // This creates bank conflicts within warp
        smem[tid * 32] = temp;
        __syncthreads(); // Ensure writes complete before next iteration
    }

    end_cycle = clock64();

    if(tid == 0) {
        *result = end_cycle - start_cycle;
    }
}

int main() {
    unsigned long long *d_result, h_result;
    cudaMalloc(&d_result, sizeof(unsigned long long));

    const int num_iterations = 10;
    unsigned long long conflict_times[num_iterations];
    unsigned long long free_times[num_iterations];

    // Warm up
    conflict_free_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
    conflict_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
    cudaDeviceSynchronize();

    // Measure conflict-free times
    for(int i = 0; i < num_iterations; i++) {
        conflict_free_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
        cudaMemcpy(&h_result, d_result, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
        free_times[i] = h_result;
    }

    // Measure conflict times
    for(int i = 0; i < num_iterations; i++) {
        conflict_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(d_result);
        cudaMemcpy(&h_result, d_result, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
        conflict_times[i] = h_result;
    }

    // Calculate medians
    // Simple bubble sort to find median
    for(int i = 0; i < num_iterations - 1; i++) {
        for(int j = 0; j < num_iterations - i - 1; j++) {
            if(free_times[j] > free_times[j+1]) {
                unsigned long long temp = free_times[j];
                free_times[j] = free_times[j+1];
                free_times[j+1] = temp;
            }
            if(conflict_times[j] > conflict_times[j+1]) {
                unsigned long long temp = conflict_times[j];
                conflict_times[j] = conflict_times[j+1];
                conflict_times[j+1] = temp;
            }
        }
    }

    unsigned long long median_free_time = free_times[num_iterations/2];
    unsigned long long median_conflict_time = conflict_times[num_iterations/2];

    // Calculate penalty per access
    // Total number of accesses = NUM_ACCESS_ITERATIONS * WARP_SIZE
    unsigned long long total_accesses = NUM_ACCESS_ITERATIONS * WARP_SIZE;

    double penalty_per_access = (double)(median_conflict_time - median_free_time) / total_accesses;

    printf("%.2f\n", penalty_per_access);

    cudaFree(d_result);
    return 0;
}
